import React from "react";

function Navbar() {
  return (
    <header style={styles.navbar}>

      {/* Logo */}
      <div style={styles.logoContainer}>
        <img
          src="https://cdn-icons-png.flaticon.com/512/2966/2966485.png"
          alt="logo"
          style={styles.logoImg}
        />
        <h2 style={styles.logoText}>DocBook</h2>
      </div>

      {/* Links */}
      <ul style={styles.navLinks}>
        <li style={styles.link}>Home</li>
        <li style={styles.link}>Doctors</li>
        <li style={styles.link}>Appointments</li>
        <li style={styles.link}>Profile</li>
      </ul>

      {/* Actions */}
      <div>
        <button style={styles.bookBtn}>Book Now</button>
        <button style={styles.logout}>Logout</button>
      </div>

    </header>
  );
}

export default Navbar;

const styles = {
  navbar: {
    backgroundColor: "white",
    padding: "15px 40px",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    boxShadow: "0 2px 10px rgba(0,0,0,0.08)",
  },

  logoContainer: {
    display: "flex",
    alignItems: "center",
    gap: "10px",
  },

  logoImg: {
    width: "35px",
    height: "35px",
  },

  logoText: {
    margin: 0,
    color: "#2563EB",
  },

  navLinks: {
    listStyle: "none",
    display: "flex",
    gap: "25px",
    margin: 0,
    padding: 0,
  },

  link: {
    cursor: "pointer",
    color: "#333",
    fontWeight: "500",
  },

  bookBtn: {
    backgroundColor: "#2563EB",
    color: "white",
    border: "none",
    padding: "8px 15px",
    borderRadius: "6px",
    marginRight: "10px",
    cursor: "pointer",
  },

  logout: {
    backgroundColor: "#e74c3c",
    color: "white",
    border: "none",
    padding: "8px 15px",
    borderRadius: "6px",
    cursor: "pointer",
  },
};
